// 이번 주 월요일 ~ 금요일 날짜 범위 계산 (yyyy-MM-dd 형식)
const now = new Date();
const dayOfWeek = now.getUTCDay(); // 0=일, 1=월, ..., 5=금
const daysFromMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;

const monday = new Date(now);
monday.setUTCDate(now.getUTCDate() - daysFromMonday);
monday.setUTCHours(0, 0, 0, 0);

// yyyy-MM-dd 형식 (NocoDB where절 호환)
const pad = (n) => String(n).padStart(2, '0');
const mondayStr = monday.getUTCFullYear() + '-' + pad(monday.getUTCMonth() + 1) + '-' + pad(monday.getUTCDate());

const weekStartKST = new Date(monday.getTime() + 9 * 60 * 60 * 1000);
const weekLabel = weekStartKST.toLocaleDateString('ko-KR', { month: 'long', day: 'numeric' });

return [{
  json: {
    weekStart: mondayStr,
    weekLabel: weekLabel + ' 주'
  }
}];

const inputData = $input.first().json;
const records = inputData.list || [];
const weekLabel = $('이번 주 날짜 범위 계산').first().json.weekLabel;

// NocoDB 에러 시 빈 배열 처리
if (inputData.error || inputData.msg) {
  return [{ json: { message: '이번 주 신규 수집된 고관련 공고가 없습니다.\n\n(관련도 50점 이상 + 기간만료 제외 기준)', hasData: false, count: 0 } }];
}

// 관련도점수 내림차순, 동점시 신청성공가능성 우선
const priority = { '높음': 3, '보통': 2, '낮음': 1 };
const sorted = [...records].sort((a, b) => {
  const scoreDiff = (b['관련도점수'] || 0) - (a['관련도점수'] || 0);
  if (scoreDiff !== 0) return scoreDiff;
  return (priority[b['신청성공가능성']] || 0) - (priority[a['신청성공가능성']] || 0);
});

const top5 = sorted.slice(0, 5);
const hasData = top5.length > 0;

if (!hasData) {
  return [{ json: { message: '이번 주 신규 수집된 고관련 공고가 없습니다.\n\n(관련도 50점 이상 + 기간만료 제외 기준)', hasData: false, count: 0 } }];
}

const today = new Date();
const todayKST = new Date(today.getTime() + 9 * 60 * 60 * 1000);
const dateStr = todayKST.toLocaleDateString('ko-KR');

let msg = '<b>[주간 TOP5 정부지원사업 리포트]</b>\n';
msg += '<i>' + dateStr + ' | ' + weekLabel + '</i>\n';
msg += '총 ' + records.length + '건 수집, 상위 ' + top5.length + '건 요약\n';
msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

top5.forEach((rec, idx) => {
  const deadline = rec['마감일'] ? new Date(rec['마감일']) : null;
  let ddayStr = '마감일 미상';
  if (deadline) {
    const dday = Math.ceil((deadline - today) / 86400000);
    if (dday < 0) ddayStr = '마감';
    else if (dday === 0) ddayStr = 'D-Day';
    else ddayStr = 'D-' + dday;
  }

  msg += '<b>' + (idx + 1) + '. ' + (rec['지원사업이름'] || '-') + '</b>\n';
  msg += '   ' + (rec['소관기관'] || '-') + ' | ' + ddayStr + '\n';
  msg += '   관련도: ' + (rec['관련도점수'] || 0) + '점 | 성공가능성: ' + (rec['신청성공가능성'] || '-') + ' | ' + (rec['카테고리'] || '-') + '\n';

  if (rec['예상지원규모']) msg += '   지원규모: ' + rec['예상지원규모'] + '\n';
  if (rec['신청자격_충족여부']) msg += '   자격충족: ' + rec['신청자격_충족여부'] + '\n';
  if (rec['핵심신청자격']) {
    const qual = rec['핵심신청자격'].length > 80 ? rec['핵심신청자격'].substring(0, 80) + '...' : rec['핵심신청자격'];
    msg += '   핵심자격: ' + qual + '\n';
  }
  if (rec['신청Link']) msg += '   <a href="' + rec['신청Link'] + '">공고 보기</a>\n';

  if (idx < top5.length - 1) msg += '\n';
});

msg += '\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
msg += '<i>NocoDB에서 신청의향=true 변경 시 서류 자동 생성</i>';

return [{ json: { message: msg, hasData: true, count: top5.length } }];
